import React, { useState, useEffect } from 'react';
import JobForm from '../components/JobForm';
import ResumeUpload from '../components/ResumeUpload';
import Dashboard from '../components/Dashboard';
import '../styles/Home.css';

function Home() {
  const [activeTab, setActiveTab] = useState('post-job');
  const [selectedJob, setSelectedJob] = useState(null);
  const [jobs, setJobs] = useState([]);
  const [refreshTrigger, setRefreshTrigger] = useState(0);

  useEffect(() => {
    fetchJobs();
  }, [refreshTrigger]);

  const fetchJobs = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/jobs');
      const data = await response.json();
      if (data.success) {
        setJobs(data.data);
      }
    } catch (error) {
      console.error('Error fetching jobs:', error);
    }
  };

  const handleJobCreated = () => {
    setRefreshTrigger(prev => prev + 1);
    setActiveTab('upload-resume');
  };

  const handleResumeUploaded = () => {
    setRefreshTrigger(prev => prev + 1);
  };

  return (
    <div className="home-container">
      <div className="welcome-section">
        <h2>Welcome to AI-Powered Resume Shortlisting</h2>
        <p>Automate your recruitment process with intelligent resume screening</p>
      </div>

      <div className="tabs">
        <button 
          className={`tab ${activeTab === 'post-job' ? 'active' : ''}`}
          onClick={() => setActiveTab('post-job')}
        >
          📝 Post Job
        </button>
        <button 
          className={`tab ${activeTab === 'upload-resume' ? 'active' : ''}`}
          onClick={() => setActiveTab('upload-resume')}
        >
          📄 Upload Resume
        </button>
        <button 
          className={`tab ${activeTab === 'dashboard' ? 'active' : ''}`}
          onClick={() => setActiveTab('dashboard')}
        >
          📊 Dashboard
        </button>
      </div>

      <div className="tab-content">
        {activeTab === 'post-job' && (
          <JobForm onJobCreated={handleJobCreated} />
        )}

        {activeTab === 'upload-resume' && (
          <ResumeUpload 
            jobs={jobs} 
            selectedJob={selectedJob}
            onResumeUploaded={handleResumeUploaded}
          />
        )}

        {activeTab === 'dashboard' && (
          <Dashboard 
            jobs={jobs}
            onJobSelect={setSelectedJob}
          />
        )}
      </div>
    </div>
  );
}

export default Home;
